class Solution:
    def shortestCompletingWord(self, licensePlate, words):
        from collections import Counter
        need = Counter(c.lower() for c in licensePlate if c.isalpha())
        best = None
        for w in words:
            wc = Counter(w)
            ok = all(wc[k] >= v for k, v in need.items())
            if ok and (best is None or len(w) < len(best)):
                best = w
        return best

