var shortestCompletingWord = function(licensePlate, words) {
    const need = {};
    for (const ch of licensePlate.toLowerCase()) {
        if (ch >= 'a' && ch <= 'z') need[ch] = (need[ch] || 0) + 1;
    }
    let ans = null;
    for (const w of words) {
        const wc = {};
        for (const ch of w) wc[ch] = (wc[ch] || 0) + 1;
        let ok = true;
        for (const k in need) {
            if ((wc[k] || 0) < need[k]) { ok = false; break; }
        }
        if (ok && (ans === null || w.length < ans.length)) ans = w;
    }
    return ans;
};
